#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,q=0;
    cin>>n;
    int a[n][4];
    for(int i=0;i<n;i++){
        cin>>a[i][0]>>a[i][1]>>a[i][2];
        a[i][3]=1;
        if(a[i][0]==0){
            a[i][3]=0;
            q+=a[i][1];
        }
        else{
            for(int j=max(0,i-45);j<i;j++){
                if(a[j][0]==0&&a[j][1]>=a[i][1]&&a[i][2]-a[j][2]<=45&&a[j][3]==0){
                    q-=a[i][1];
                    a[j][3]=1;
                    break;
                }
            }
            q+=a[i][1];
        }
    }
    cout<<q;
    return 0;
}
